package com.chaobo.scm.supplier.application.contract;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.integration.InboundEventPayloadStore;import com.chaobo.scm.supplier.application.masterdata.MasterDataEventConsumeLogPort;import com.chaobo.scm.supplier.application.shared.CommandContext;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.Set;
@Service public class ContractApprovalEventConsumerApplicationService {public static final String CONSUMER="supplier-contract-approval";private final MasterDataEventConsumeLogPort inbox;private final InboundEventPayloadStore payloads;private final SupplierContractApplicationService contracts;public ContractApprovalEventConsumerApplicationService(MasterDataEventConsumeLogPort inbox,InboundEventPayloadStore payloads,SupplierContractApplicationService contracts){this.inbox=inbox;this.payloads=payloads;this.contracts=contracts;}@Transactional public void consume(ContractApprovalEvent event){if(!"IAM".equals(event.sourceSystem()))throw new BusinessException(ErrorCode.FORBIDDEN,"合同审批事件来源必须为IAM");var claim=inbox.claim("IAM",event.eventCode(),event.eventType(),CONSUMER,"IAM:"+event.eventCode());if(claim==MasterDataEventConsumeLogPort.ClaimResult.ALREADY_SUCCEEDED)return;if(claim==MasterDataEventConsumeLogPort.ClaimResult.IN_PROGRESS)throw new BusinessException(ErrorCode.IDEMPOTENCY_CONFLICT,"合同审批事件正在处理");payloads.save("IAM",event.eventCode(),CONSUMER,event);try{var c=new CommandContext(0,"IAM",0,null,event.eventCode(),null,"IAM:"+event.eventCode(),Set.of("supplier:contract:approve"));if(event.approved())contracts.approve(event.contractId(),event.contractVersion(),c);else contracts.rejectApproval(event.contractId(),event.contractVersion(),event.comment(),c);inbox.markSucceeded("IAM",event.eventCode(),CONSUMER,false);}catch(RuntimeException ex){inbox.recordFailure("IAM",event.eventCode(),event.eventType(),CONSUMER,"IAM:"+event.eventCode(),ex.getMessage());throw ex;}}}
